6: import { CodeAction, CodeActionKind, CodeActionProvider, Diagnostic, DiagnosticCollection, DiagnosticSeverity, Disposable, Range, Selection, TextDocument, Uri, WorkspaceEdit, l10n, languages, workspace } from 'vscode';
7: import { mapEvent, filterEvent, dispose } from './util';
8: import { Model } from './model';
9: 
10: export enum DiagnosticCodes {
11: 	empty_message = 'empty_message',
12: 	line_length = 'line_length'
13: }
14: 
15: export class GitCommitInputBoxDiagnosticsManager {
16: 
17: 	private readonly diagnostics: DiagnosticCollection;
18: 	private readonly severity = DiagnosticSeverity.Warning;
19: 	private readonly disposables: Disposable[] = [];
20: 
21: 	constructor(private readonly model: Model) {
22: 		this.diagnostics = languages.createDiagnosticCollection();
23: 
24: 		this.migrateInputValidationSettings()
25: 			.then(() => {
26: 				mapEvent(filterEvent(workspace.onDidChangeTextDocument, e => e.document.uri.scheme === 'vscode-scm'), e => e.document)(this.onDidChangeTextDocument, this, this.disposables);
27: 				filterEvent(workspace.onDidChangeConfiguration, e => e.affectsConfiguration('git.inputValidation') || e.affectsConfiguration('git.inputValidationLength') || e.affectsConfiguration('git.inputValidationSubjectLength'))(this.onDidChangeConfiguration, this, this.disposables);
28: 			});
29: 	}
30: 
31: 	public getDiagnostics(uri: Uri): ReadonlyArray<Diagnostic> {
32: 		return this.diagnostics.get(uri) ?? [];
33: 	}
34: 
35: 	private async migrateInputValidationSettings(): Promise<void> {
36: 		try {
37: 			const config = workspace.getConfiguration('git');
38: 			const inputValidation = config.inspect<'always' | 'warn' | 'off' | boolean>('inputValidation');
39: 
40: 			if (inputValidation === undefined) {
41: 				return;
42: 			}
43: 
44: 			// Workspace setting
45: 			if (typeof inputValidation.workspaceValue === 'string') {
46: 				await config.update('inputValidation', inputValidation.workspaceValue !== 'off', false);
47: 			}
48: 
49: 			// User setting
50: 			if (typeof inputValidation.globalValue === 'string') {
51: 				await config.update('inputValidation', inputValidation.workspaceValue !== 'off', true);
52: 			}
53: 		} catch { }
54: 	}
55: 
56: 	private onDidChangeConfiguration(): void {
57: 		for (const repository of this.model.repositories) {
58: 			this.onDidChangeTextDocument(repository.inputBox.document);
59: 		}
60: 	}
61: 
62: 	private onDidChangeTextDocument(document: TextDocument): void {
63: 		const config = workspace.getConfiguration('git');
64: 		const inputValidation = config.get<boolean>('inputValidation', false);
65: 		if (!inputValidation) {
66: 			this.diagnostics.set(document.uri, undefined);
67: 			return;
68: 		}
69: 
70: 		if (/^\s+$/.test(document.getText())) {
71: 			const documentRange = new Range(document.lineAt(0).range.start, document.lineAt(document.lineCount - 1).range.end);
72: 			const diagnostic = new Diagnostic(documentRange, l10n.t('Current commit message only contains whitespace characters'), this.severity);
73: 			diagnostic.code = DiagnosticCodes.empty_message;
74: 
75: 			this.diagnostics.set(document.uri, [diagnostic]);
76: 			return;
77: 		}
78: 
79: 		const diagnostics: Diagnostic[] = [];
80: 		const inputValidationLength = config.get<number>('inputValidationLength', 50);
81: 		const inputValidationSubjectLength = config.get<number | undefined>('inputValidationSubjectLength', undefined);
82: 
83: 		for (let index = 0; index < document.lineCount; index++) {
84: 			const line = document.lineAt(index);
85: 			const threshold = index === 0 ? inputValidationSubjectLength ?? inputValidationLength : inputValidationLength;
86: 
87: 			if (line.text.length > threshold) {
88: 				const diagnostic = new Diagnostic(line.range, l10n.t('{0} characters over {1} in current line', line.text.length - threshold, threshold), this.severity);
89: 				diagnostic.code = DiagnosticCodes.line_length;
90: 
91: 				diagnostics.push(diagnostic);
92: 			}
93: 		}
94: 
95: 		this.diagnostics.set(document.uri, diagnostics);
96: 	}
97: 
98: 	dispose() {
99: 		dispose(this.disposables);
100: 	}
101: }
