## Usage Examples

### Basic Example: Creating and Publishing Diagnostics

```typescript
import * as vscode from 'vscode';

export function activate(context: vscode.ExtensionContext) {
    // Create a diagnostic collection
    const diagnostics = vscode.languages.createDiagnosticCollection('myExtension');
    context.subscriptions.push(diagnostics);

    // Listen to file changes and validate
    vscode.workspace.onDidChangeTextDocument(event => {
        const doc = event.document;

        // Simple validation: flag lines with TODO comments as information
        const diags: vscode.Diagnostic[] = [];
        for (let i = 0; i < doc.lineCount; i++) {
            const line = doc.lineAt(i);
            if (line.text.includes('TODO')) {
                const range = new vscode.Range(i, 0, i, line.text.length);
                const diagnostic = new vscode.Diagnostic(
                    range,
                    'TODO: Address this item',
                    vscode.DiagnosticSeverity.Information
                );
                diagnostic.source = 'myExtension';
                diags.push(diagnostic);
            }
        }

        // Publish diagnostics
        diagnostics.set(doc.uri, diags);
    }, null, context.subscriptions);
}
```

---

### Advanced Example: Diagnostics with Related Information and Code Actions

```typescript
import * as vscode from 'vscode';

export function activate(context: vscode.ExtensionContext) {
    const diagnostics = vscode.languages.createDiagnosticCollection('duplicateChecker');
    context.subscriptions.push(diagnostics);

    // Validate file for duplicate declarations
    vscode.workspace.onDidChangeTextDocument(event => {
        const doc = event.document;
        const declarations = new Map<string, vscode.Range[]>();

        // Find all function declarations
        for (let i = 0; i < doc.lineCount; i++) {
            const line = doc.lineAt(i).text;
            const match = line.match(/function\s+(\w+)\s*\(/);
            if (match) {
                const name = match[1];
                if (!declarations.has(name)) {
                    declarations.set(name, []);
                }
                declarations.get(name)!.push(doc.lineAt(i).range);
            }
        }

        // Report duplicates
        const diags: vscode.Diagnostic[] = [];
        for (const [name, ranges] of declarations.entries()) {
            if (ranges.length > 1) {
                // Create diagnostic for each duplicate
                for (let i = 1; i < ranges.length; i++) {
                    const diagnostic = new vscode.Diagnostic(
                        ranges[i],
                        `Duplicate function declaration: '${name}' is already declared`,
                        vscode.DiagnosticSeverity.Error
                    );
                    diagnostic.code = { value: 'duplicate-declaration', target: vscode.Uri.parse('https://example.com/duplicate') };
                    diagnostic.source = 'duplicateChecker';

                    // Add related information pointing to first declaration
                    diagnostic.relatedInformation = [
                        new vscode.DiagnosticRelatedInformation(
                            new vscode.Location(doc.uri, ranges[0]),
                            `First declaration of '${name}'`
                        )
                    ];

                    diags.push(diagnostic);
                }
            }
        }

        diagnostics.set(doc.uri, diags);
    }, null, context.subscriptions);

    // Register code actions for diagnostics
    vscode.languages.registerCodeActionsProvider('*', {
        provideCodeActions(doc, range, context) {
            const codeActions: vscode.CodeAction[] = [];

            for (const diagnostic of context.diagnostics) {
                if (diagnostic.code?.value === 'duplicate-declaration') {
                    const action = new vscode.CodeAction(
                        'Remove duplicate declaration',
                        vscode.CodeActionKind.QuickFix
                    );
                    action.diagnostics = [diagnostic];
                    action.command = {
                        title: 'Remove duplicate',
                        command: 'editor.action.deleteLines'
                    };
                    codeActions.push(action);
                }
            }

            return codeActions;
        }
    });
}
```

